const now = Date.now();
const seconds = Math.floor(now / 1000);
const nanoseconds = (now % 1000) * 1e6;

const tbuf = Buffer.alloc(10);
tbuf.writeUIntBE(seconds, 0, 6);
tbuf.writeUInt32BE(nanoseconds, 6);

let tempVal = flow.get('lastTempVal');
if (typeof tempVal !== 'number') {
    tempVal = 26;  // default starting value
}

// Apply random adjustment
const rand = Math.random();
if (rand <= 0.2) {
    tempVal = tempVal - .5;
}
else if (rand <= 0.4) {
    tempVal = tempVal - 0.25;
}
else if (rand <= .6) {
    tempVal = tempVal;
}
else if (rand <= 0.8) {
    tempVal = tempVal + 0.25;
}
else {
    tempVal = tempVal + .5;
}

// Store updated value for next run
flow.set('lastTempVal', tempVal);

